    @pytest.mark.anyio
    async def test_uuid_filename_prevents_path_traversal(self) -> None:
        """上传 filename 含 ../evil → UUID 替代，无路径遍历。

        直接验证代码中的文件名生成逻辑：
        Line 88-89: ext = Path(file.filename or "").suffix
                    safe_name = f"{uuid.uuid4().hex}{ext}"
        """
        import uuid
        from pathlib import Path

        # 模拟用户传入的恶意文件名
        evil_filenames = [
            "../../../etc/passwd.jpg",
            "..\\..\\windows\\system32\\config.jpg",
            "/etc/shadow.png",
            "normal.jpg",
        ]

        for fname in evil_filenames:
            ext = Path(fname).suffix
            safe_name = f"{uuid.uuid4().hex}{ext}"
            # 安全文件名不应包含任何路径分隔符
            assert "/" not in safe_name, f"安全文件名包含 /: {safe_name}"
            assert "\\" not in safe_name, f"安全文件名包含 \\: {safe_name}"
            assert ".." not in safe_name, f"安全文件名包含 ..: {safe_name}"
            # UUID hex 部分应为 32 字符
            stem = Path(safe_name).stem
            assert len(stem) == 32, f"UUID hex 应为 32 字符: {stem}"


